    13→pub async fn run_merge_gate(
    14→    cards_dir: &Path,
    15→    poll_ms: u64,
    16→    once: bool,
    17→    vcs_engine: VcsEngine,
    18→) -> anyhow::Result<()> {
    19→    paths::ensure_cards_layout(cards_dir)?;
    20→
    21→    let done_dir = cards_dir.join("done");
    22→    let merged_dir = cards_dir.join("merged");
    23→    let failed_dir = cards_dir.join("failed");
    24→    let mg_lineage_enabled = bop_core::lineage::is_enabled(cards_dir);
    25→
    26→    loop {
    27→        let mut mg_lineage_events: Vec<bop_core::lineage::RunEvent> = Vec::new();
    28→        let mut mg_record =
    29→            |meta: &bop_core::Meta, from: &str, to: &str, card_dir: Option<&Path>| {
    30→                if mg_lineage_enabled {
    31→                    let et = bop_core::lineage::event_type_for(from, to);
    32→                    mg_lineage_events.push(bop_core::lineage::build_run_event_with_dir(
    33→                        et, meta, from, to, card_dir,
    34→                    ));
    35→                }
    36→            };
    37→
    38→        if let Ok(entries) = fs::read_dir(&done_dir) {
    39→            for ent in entries.flatten() {
    40→                let card_dir = ent.path();
    41→                if !card_dir.is_dir() {
    42→                    continue;
    43→                }
    44→                if card_dir.extension().and_then(|s| s.to_str()).unwrap_or("") != "bop" {
    45→                    continue;
    46→                }
    47→
    48→                let name = match card_dir.file_name().and_then(|s| s.to_str()) {
    49→                    Some(n) => n.to_string(),
    50→                    None => continue,
    51→                };
    52→
    53→                let mut meta = match bop_core::read_meta(&card_dir) {
    54→                    Ok(m) => m,
    55→                    Err(_) => {
    56→                        let failed_path = failed_dir.join(&name);
    57→                        let _ = fs::rename(&card_dir, &failed_path);
    58→                        quicklook::render_card_thumbnail(&failed_path);
    59→                        // No meta available for lineage event here
    60→                        continue;
    61→                    }
    62→                };
    63→
    64→                fs::create_dir_all(card_dir.join("logs"))?;
    65→                fs::create_dir_all(card_dir.join("output"))?;
    66→
    67→                let workdir = {
    68→                    if let Some(ref p) = meta.workspace_path {
    69→                        let candidate = PathBuf::from(p);
    70→                        if candidate.exists() {
    71→                            candidate
    72→                        } else {
    73→                            let ws = card_dir.join("workspace");
    74→                            if ws.exists() {
    75→                                ws
    76→                            } else {
    77→                                card_dir.clone()
    78→                            }
    79→                        }
    80→                    } else {
