    92→                // Heal stale working copy before running ACs — concurrent jj ops
    93→                // often leave workspaces stale, causing `jj log` to fail.
    94→                if matches!(vcs_engine, VcsEngine::Jj) {
    95→                    let _ = TokioCommand::new("jj")
