   165→                    continue;
   166→                }
   167→                meta.policy_result = Some("pass".to_string());
   168→
   169→                let ws_path = if let Some(ref p) = meta.workspace_path {
   170→                    PathBuf::from(p)
   171→                } else {
   172→                    card_dir.join("workspace")
   173→                };
