   180→                                meta.failure_reason = Some("git_root_not_found".to_string());
   181→                                meta.policy_result = Some("failed".to_string());
   182→                                let _ = write_meta(&card_dir, &meta);
   183→                                let failed_path = failed_dir.join(&name);
   184→                                let _ = fs::rename(&card_dir, &failed_path);
