    43→pub fn print_state_group(dir: &Path, state: &str, team_prefix: Option<&str>) -> anyhow::Result<()> {
    44→    let state_dir = dir.join(state);
    45→    if !state_dir.exists() {
    46→        return Ok(());
    47→    }
    48→
    49→    let mut cards: Vec<bop_core::Meta> = Vec::new();
    50→    if let Ok(entries) = fs::read_dir(&state_dir) {
    51→        for entry in entries.flatten() {
    52→            let p = entry.path();
    53→            if p.is_dir() && p.extension().is_some_and(|e| e == "bop" || e == "jobcard") {
    54→                if let Ok(meta) = bop_core::read_meta(&p) {
    55→                    cards.push(meta);
    56→                }
    57→            }
    58→        }
    59→    }
    60→
    61→    let header = match team_prefix {
    62→        Some(team) => format!("{}/{}", team, state),
    63→        None => state.to_string(),
    64→    };
    65→
    66→    println!("{} ({})", header, cards.len());
    67→    for meta in &cards {
    68→        let glyph = meta.glyph.as_deref().unwrap_or("  ");
    69→        let token = meta.token.as_deref().unwrap_or(" ");
    70→        let id_display = if meta.id.len() > 32 {
    71→            &meta.id[..32]
    72→        } else {
    73→            &meta.id
    74→        };
    75→        let pri = meta
    76→            .priority
    77→            .map(|p| format!("P{}", p))
    78→            .unwrap_or_else(|| "--".into());
    79→        let pct = meta.progress.unwrap_or(0);
    80→        let filled = (pct as usize * 8) / 100;
    81→        let bar: String = (0..8)
    82→            .map(|i| if i < filled { '\u{2588}' } else { '\u{2591}' })
    83→            .collect();
    84→        let pct_str = if pct > 0 {
    85→            format!("{}%", pct)
    86→        } else {
    87→            String::new()
    88→        };
    89→        println!(
    90→            "  {} {}  {:<32}  {:<12} {:<3} {} {}",
    91→            glyph, token, id_display, meta.stage, pri, bar, pct_str
    92→        );
    93→    }
    94→    println!();
    95→    Ok(())
    96→}
